       }

-      this.ws!.send(JSON.stringify(message))
+      try {
+        ws.send(JSON.stringify(message))
+      } catch (err) {
+        clearTimeout(timeoutHandle)
+        this.pendingRequests.delete(id)
+        reject(err instanceof Error ? err : new Error(String(err)))
+      }
     })
   }
